        let f = self.get_free_pos();
        let f = match f {
            None => {
                // C: rehash(L, t, key); luaH_set(L, t, key, value); return;
                self.rehash(state, key)?;
                return self.set(state, key, value);
            }
            Some(idx) => idx,
        };

